import assert from "node:assert/strict";
import test from "node:test";

import { WorkspaceSession } from "../src/session.ts";

test("reset restores pristine defaults after nested mutations", () => {
  const session = new WorkspaceSession();
  session.addColumn("priority");
  session.setDensity("compact");
  session.reset();

  assert.deepEqual(session.snapshot(), {
    name: "Untitled",
    columns: ["title", "status"],
    preferences: { density: "comfortable", showHints: true },
  });
});

test("resetting from a snapshot keeps later edits local to the session", () => {
  const restored = {
    name: "Ops",
    columns: ["incident"],
    preferences: { density: "compact" as const, showHints: false },
  };
  const session = new WorkspaceSession();
  session.reset(restored);
  session.addColumn("owner");
  session.setDensity("comfortable");

  assert.deepEqual(restored, {
    name: "Ops",
    columns: ["incident"],
    preferences: { density: "compact", showHints: false },
  });
});
